/**
 * Check if a given slug is a valid location slug
 * @param {string} slug - The location slug to validate
 * @returns {boolean} True if valid, false otherwise
 */
export const isValidLocationSlug = (slug) => {
  if (!slug || typeof slug !== 'string') {
    return false;
  }
  return allLocationSlugs.includes(slug.toLowerCase());
};

/**
 * Format a location slug into a readable location name
 * @param {string} slug - The location slug (without 'escorts-in-' prefix)
 * @returns {string} Formatted location name
 */
export const formatLocationName = (slug) => {
  if (!slug) return '';
  
  return slug
    .split('-')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

/**
 * Get all location slugs
 * @returns {array} Array of all location slugs
 */
export const getAllLocationSlugs = () => {
  return [...allLocationSlugs];
};

/**
 * Check if two locations are the same (case-insensitive)
 * @param {string} slug1 - First location slug
 * @param {string} slug2 - Second location slug
 * @returns {boolean} True if same location, false otherwise
 */
export const isSameLocation = (slug1, slug2) => {
  return slug1?.toLowerCase() === slug2?.toLowerCase();
};

